me":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"3a57a18f-c869-4a80-9da0-a11a0ad2f9bd"},{"version":"CommandV1","origId":1083584440949919,"guid":"0e8ca323-5155-4d6d-be35-e12a259aff0f","subtype":"command","commandType":"auto","position":5.0,"command":"%md\n## Option 1: StringIndexer, OneHotEncoder, and VectorAssembler\n\nHere, we are going to One Hot Encode (OHE) our categorical variables. The first approach we are going to use will combine StringIndexer, OneHotEncoder, and VectorAssembler.\n\nFirst we need to use `StringIndexer` to map a string column of labels to an ML column of label indices [Python](https://spark.apache.org/docs/latest/api/python/pyspark.ml.html#pyspark.ml.feature.StringIndexer)/[Scala](https://spark.apache.org/docs/latest/api/scala/#org.apache.spark.ml.feature.StringIndexer).\n\nThen, we can apply the `OneHotEncoder` to the output of the StringIndexer [Python](https://spark.apache.org/docs/latest/api/python/pyspark.ml.html#pyspark.ml.feature.OneHotEncoder)/[Scala](https://spark.apache.org/docs/latest/api/scala/#org.apache.spark.ml.feature.OneHotEncoder).","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"1250206c-5814-4344-a1dc-54fe4ebb8408"},{"version":"CommandV1","origId":1083584440949920,"guid":"fb61d5ed-c3cc-44bd-9790-90ac520c5a97","subtype":"command","commandType":"auto","position":6.0,"command":"import org.apache.spark.ml.feature.{OneHotEncoder, StringIndexer}\n\nval categoricalCols = trainDF.dtypes.filter(_._2 == \"StringType\").map(_._1)\nval indexOutputCols = categoricalCols.map(_ + \"Index\")\nval oheOutputCols = categoricalCols.map(_ + \"OHE\")\n\nval stringIndexer = new StringIndexer()\n  .setInputCols(categoricalCols)\n  .setOutputCols(indexOutputCols)\n  .setHandleInvalid(\"skip\")\n\nval oheEncoder = new OneHotEncoder()\n  .setInputCols(indexOutputCols)\n  .setOutputCols(oheOutputCols)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"b125f56d-e58d-4611-834b-b1567ced0959"},{"version":"CommandV1","origId":1083584440949921,"guid":"52316d76-e1ef-43ec-9f23-f70e5fd81f7d","subtype":"command","commandType":"auto","position":7.0,"command":"%md\nNow we can combine our OHE categorical features with our numeric features.","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"6545b57a-43ea-43d9-b695-be6aa725d23c"},{"version":"CommandV1","origId":1083584440949922,"guid":"cc4f01e2-b9ce-481f-a94d-7ca90b827b18","subtype":"command","commandType":"auto","position":8.0,"command":"import org.apache.spark.ml.feature.VectorAssembler\n\nval numericCols = trainDF.dtypes.filter{ case (field, dataType) => \n  dataType == \"DoubleType\" && field != \"price\"}.map(_._1)\nval assemblerInputs = oheOutputCols ++ numericCols\nval vecAssembler = new VectorAssembler()\n  .setInputCols(assemblerInputs)\n  .setOutputCol(\"features\")","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"82fa25ad-fc38-4191-b630-6d4a9a5c4ae9"},{"version":"CommandV1","origId":1083584440949923,"guid":"5a5fe318-b820-4547-81b5-f85fe0e45445","subtype":"command","commandType":"auto","position":9.0,"command":"%md\n## Option 2: RFormula\nInstead of manually specifying which columns are categorical to the StringIndexer and OneHotEncoder, RFormula can do that automatically for you [Python](https://spark.apache.org/docs/latest/api/python/pyspark.ml.html#pyspark.ml.feature.RFormula)/[Scala](https://spark.apache.org/docs/latest/api/scala/#org.apache.spark.ml.feature.RFormula).\n\nWith RFormula, if you have any columns of type String, it treats it as a categorical feature and string indexes & one hot encodes it for us. Otherwise, it leaves as it is. Then it combines all of one-hot encoded features and numeric features into a single vector, called `features`.","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"9c098db6-fc38-49cb-8de2-d3d96f559667"},{"version":"CommandV1","origId":1083584440949924,"guid":"d383f384-bba2-4447-b215-2f1fd3d6797c","subtype":"command","commandType":"auto","position":10.0,"command":"import org.apache.spark.ml.feature.RFormula\n\nval rFormula = new RFormula()\n  .setFormula(\"price ~ .\")\n  .setFeaturesCol(\"features\")\n  .setLabelCol(\"price\")\n  .setHandleInvalid(\"skip\")","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"69cda1d1-f20e-460c-b7ff-a90ba41b3032"},{"version":"CommandV1","origId":1083584440949925,"guid":"05e9d8d4-a2f1-4500-b241-d3a3fe66dfcf","subtype":"command","commandType":"auto","position":11.0,"command":"%md\n## Linear Regression\n\nNow that we have all of our features, let's build a linear regression model.","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"f41cc5b9-3904-4dec-af67-8520e5d759b4"},{"version":"CommandV1","origId":1083584440949926,"guid":"e186fc7c-7940-42d6-8f54-c9bef5c26e3d","subtype":"command","commandType":"auto","position":12.0,"command":"import org.apache.spark.ml.regression.LinearRegression\n\nval lr = new LinearRegression()\n  .setLabelCol(\"price\")\n  .setFeaturesCol(\"features\")","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"aaa8b84a-4979-4d44-82f3-cefea8167019"},{"version":"CommandV1","origId":1083584440949927,"guid":"3bfa4960-6bc2-44c7-9b32-4d0e0e6ab345","subtype":"command","commandType":"auto","position":13.0,"command":"%md\n## Pipeline\n\nLet's put all these stages in a Pipeline. A `Pipeline` is a way of organizing all of our transformers and estimators [Python](https://spark.apache.org/docs/latest/api/python/pyspark.ml.html#pyspark.ml.Pipeline)/[Scala](https://spark.apache.org/docs/latest/api/scala/#org.apache.spark.ml.Pipeline).\n\nVerify you get the same results with Option 1 (StringIndexer, OneHotEncoderEstimator, and VectorAssembler) and Option 2 (RFormula)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"42dce147-18e1-47c5-8b05-a3dcd0b2661d"},{"version":"CommandV1","origId":1083584440949928,"guid":"c5f6e60e-500d-4eb4-a97e-c4bd8ff078e8","subtype":"command","commandType":"auto","position":14.0,"command":"// Option 1: StringIndexer + OHE + VectorAssembler\nimport org.apache.spark.ml.Pipeline\n\nval stages = Array(stringIndexer, oheEncoder, vecAssembler,  lr)\n\nval pipeline = new Pipeline()\n  .setStages(stages)\n\nval pipelineModel = pipeline.fit(trainDF)\nval predDF = pipelineModel.transform(testDF)\npredDF.select(\"features\", \"price\", \"prediction\").show(5)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"57857304-d70a-48ed-a176-4dce98ad41e2"},{"version":"CommandV1","origId":1083584440949929,"guid":"8712830a-dd83-43f2-9bc9-3cd6307115bc","subtype":"command","commandType":"auto","position":15.0,"command":"// Option 2: RFormula\nimport org.apache.spark.ml.Pipeline\n\nval pipeline = new Pipeline().setStages(Array(rFormula, lr))\n\nval pipelineModel = pipeline.fit(trainDF)\nval predDF = pipelineModel.transform(testDF)\npredDF.select(\"features\", \"price\", \"prediction\").show(5)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"44bff430-1705-49e1-a0e2-485473f4aa8a"},{"version":"CommandV1","origId":1083584440949930,"guid":"e2b04b26-90f1-4703-bb99-ebab0a644af7","subtype":"command","commandType":"auto","position":16.0,"command":"%md\n## Evaluate Model: RMSE","commandVersion":0,"state":"finishe